-- 1. Load new data into a temporary staging table
CREATE TEMP TABLE staging_events (LIKE events);
COPY staging_events FROM STDIN WITH CSV;

-- 2. Upsert from staging to production table
INSERT INTO events (id, name, ts)
SELECT id, name, ts FROM staging_events
ON CONFLICT (id) DO UPDATE
  SET name = EXCLUDED.name,
      ts   = EXCLUDED.ts;

-- 3. Temp table is dropped automatically at session end

BEGIN;
TRUNCATE TABLE product_catalog;
COPY product_catalog FROM STDIN WITH CSV HEADER;
COMMIT;

from tenacity import retry, stop_after_attempt, wait_exponential

@retry(stop=stop_after_attempt(3), wait=wait_exponential(multiplier=1, min=2, max=30))
def load_with_retry(df, engine):
    with engine.begin() as conn:
        df.to_sql("events", con=conn, if_exists="append", index=False, method="multi")
